export const apiHtml = "<h1>Fabritor AI Agent API 文档</h1>\n<p>本文档描述了为支持通过 chrome-devtools-mcp 进行 AI agent 自动化而添加的 API 和增强功能。</p>\n<h2>概述</h2>\n<p>Fabritor 编辑器现在在 <code>window.fabritor</code> 处暴露了一个全面的 API，用于程序化控制，同时提供稳定的 DOM 选择器用于 UI 自动化。</p>\n<h2>1. 全局 API (<code>window.fabritor</code>)</h2>\n<p>全局 API 提供对编辑器的直接访问，无需依赖 DOM 操作。</p>\n<h3>基本结构</h3>\n<pre><code class=\"language-typescript\">window.fabritor = {\r\n  version: '3.0.0',\r\n  canvas: CanvasAPI,\r\n  actions: ActionsAPI,\r\n  history: HistoryAPI,\r\n  events: EventsAPI,\r\n  export: ExportAPI,\r\n  isReady(): boolean\r\n}\n</code></pre>\n<h3>Canvas API - 查询画布</h3>\n<pre><code class=\"language-javascript\">// 获取所有对象\r\nconst objects = window.fabritor.canvas.getObjects();\r\n// 返回: [{ id, type, left, top, width, height, ... }, ...]\r\n\r\n// 按类型获取对象\r\nconst textObjects = window.fabritor.canvas.getObjectsByType('f-text');\r\nconst imageObjects = window.fabritor.canvas.getObjectsByType('f-image');\r\n\r\n// 获取当前选中的对象\r\nconst selected = window.fabritor.canvas.getActiveObject();\r\n\r\n// 根据 ID 获取对象\r\nconst obj = window.fabritor.canvas.getObjectById('obj_1234567890_1');\r\n\r\n// 获取画布尺寸\r\nconst dims = window.fabritor.canvas.getDimensions();\r\n// 返回: { width, height }\r\n\r\n// 获取缩放级别\r\nconst zoom = window.fabritor.canvas.getZoom();\r\n\r\n// 获取完整画布状态\r\nconst state = window.fabritor.canvas.getState();\r\n// 返回: { width, height, zoom, objectCount, selectedIds }\n</code></pre>\n<h3>Actions API - 操作对象</h3>\n<pre><code class=\"language-javascript\">// 选中一个对象\r\nwindow.fabritor.actions.selectObject('obj_1234567890_1');\r\n\r\n// 选中多个对象\r\nwindow.fabritor.actions.selectObjects(['obj_1', 'obj_2', 'obj_3']);\r\n\r\n// 取消所有选中\r\nwindow.fabritor.actions.deselectAll();\r\n\r\n// 删除一个对象\r\nwindow.fabritor.actions.deleteObject('obj_1234567890_1');\r\n\r\n// 删除多个对象\r\nwindow.fabritor.actions.deleteObjectIds(['obj_1', 'obj_2']);\r\n\r\n// 设置单个属性\r\nwindow.fabritor.actions.setObjectProperty('obj_123', 'left', 100);\r\nwindow.fabritor.actions.setObjectProperty('obj_123', 'textAlign', 'left');\r\n\r\n// 设置多个属性\r\nwindow.fabritor.actions.setObjectProperties('obj_123', {\r\n  left: 100,\r\n  top: 200,\r\n  opacity: 0.8\r\n});\r\n\r\n// 批量更新指定类型的所有对象\r\n// 示例：将所有文本对象设置为左对齐\r\nwindow.fabritor.actions.updateObjectsByType('f-text', { textAlign: 'left' });\r\n\r\n// 示例：设置所有文本对象的X坐标\r\nwindow.fabritor.actions.updateObjectsByType('f-text', { left: 20 });\r\n\r\n// 复制对象\r\nwindow.fabritor.actions.duplicateObject('obj_123');\r\n\r\n// 移动图层顺序\r\nwindow.fabritor.actions.moveObject('obj_123', 'up');      // 向上移动一层\r\nwindow.fabritor.actions.moveObject('obj_123', 'down');    // 向下移动一层\r\nwindow.fabritor.actions.moveObject('obj_123', 'front');  // 移到顶层\r\nwindow.fabritor.actions.moveObject('obj_123', 'back');   // 移到底层\r\n\r\n// 组合对象\r\nwindow.fabritor.actions.groupObjectIds(['obj_1', 'obj_2']);\r\n\r\n// 取消组合\r\nwindow.fabritor.actions.ungroupObject('obj_group_id');\r\n\r\n// 清空画布\r\nwindow.fabritor.actions.clearCanvas();\n</code></pre>\n<h3>History API - 撤销/重做</h3>\n<pre><code class=\"language-javascript\">// 撤销上一步操作\r\nwindow.fabritor.history.undo();\r\n\r\n// 重做\r\nwindow.fabritor.history.redo();\r\n\r\n// 清空历史\r\nwindow.fabritor.history.clear();\r\n\r\n// 获取历史状态\r\nconst historyState = window.fabritor.history.getState();\r\n// 返回: { canUndo: boolean, canRedo: boolean, size: number }\n</code></pre>\n<h3>Events API - 订阅画布事件</h3>\n<pre><code class=\"language-javascript\">// 订阅事件\r\nwindow.fabritor.events.on('object:modified', (data) => {\r\n  console.log('对象已修改:', data);\r\n});\r\n\r\nwindow.fabritor.events.on('selection:created', (data) => {\r\n  console.log('已创建选择:', data);\r\n});\r\n\r\n// 取消订阅\r\nconst callback = (data) => console.log(data);\r\nwindow.fabritor.events.on('object:added', callback);\r\nwindow.fabritor.events.off('object:added', callback);\r\n\r\n// 订阅一次\r\nwindow.fabritor.events.once('object:removed', (data) => {\r\n  console.log('对象被删除（仅一次）');\r\n});\r\n\r\n// 触发自定义事件\r\nwindow.fabritor.events.emit('custom:event', { data: 'value' });\n</code></pre>\n<p>可用事件：</p>\n<ul>\n<li><code>object:added</code> - 对象添加到画布</li>\n<li><code>object:modified</code> - 对象被修改</li>\n<li><code>object:removed</code> - 对象被删除</li>\n<li><code>object:selected</code> - 对象被选中</li>\n<li><code>object:deselected</code> - 对象取消选中</li>\n<li><code>selection:created</code> - 创建选择</li>\n<li><code>selection:updated</code> - 更新选择</li>\n<li><code>selection:cleared</code> - 清除选择</li>\n<li><code>fabritor:object:modified</code> - 自定义修改事件</li>\n<li><code>fabritor:group</code> - 对象组合</li>\n<li><code>fabritor:ungroup</code> - 取消组合</li>\n</ul>\n<h3>Export API - 导出画布</h3>\n<pre><code class=\"language-javascript\">// 导出为图片\r\nconst imgDataUrl = window.fabritor.export.toImg({\r\n  format: 'png',  // 或 'jpeg'\r\n  quality: 1\r\n});\r\n\r\n// 导出为 SVG\r\nconst svgDataUrl = window.fabritor.export.toSvg();\r\n\r\n// 导出为 JSON\r\nconst json = window.fabritor.export.toJSON();\r\n\r\n// 从 JSON 加载\r\nawait window.fabritor.export.loadFromJSON(json);\n</code></pre>\n<h2>2. DOM 选择器 (<code>data-testid</code>)</h2>\n<p>为 AI agent 可以定位的 UI 元素提供稳定的选择器。</p>\n<h3>面板元素</h3>\n<pre><code class=\"language-javascript\">// 线条工具\r\ndocument.querySelector('[data-testid=\"fabritor-btn-line-line\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-btn-line-dash-line\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-btn-line-arrow-line-1\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-btn-line-arrow-line-2\"]');\r\n\r\n// 形状工具\r\ndocument.querySelector('[data-testid=\"fabritor-btn-shape-rect\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-btn-shape-circle\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-btn-shape-triangle\"]');\r\n// ... 更多\n</code></pre>\n<h3>设置器元素</h3>\n<pre><code class=\"language-javascript\">// 通用设置器\r\ndocument.querySelector('[data-testid=\"fabritor-btn-align-left\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-btn-align-right\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-btn-align-center\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-btn-align-top\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-btn-align-bottom\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-btn-center\"]');\r\n\r\n// 位置设置器\r\ndocument.querySelector('[data-testid=\"fabritor-input-width\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-input-height\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-input-x\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-input-y\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-input-angle\"]');\r\n\r\n// 控制按钮\r\ndocument.querySelector('[data-testid=\"fabritor-btn-lock\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-btn-copy\"]');\r\ndocument.querySelector('[data-testid=\"fabritor-btn-delete\"]');\r\n\r\n// 文本对齐\r\ndocument.querySelector('[data-testid=\"fabritor-text-align\"]');\n</code></pre>\n<h2>3. 对象类型列表</h2>\n<p>画布支持以下对象类型：</p>\n<h3>基础图形</h3>\n<p>| 类型 | 类型标识 | 说明 |\r\n|------|----------|------|\r\n| 文本框 | <code>f-text</code> | 文字对象，支持多行、样式 |\r\n| 图片 | <code>f-image</code> | 图片对象，支持边框、裁剪、滤镜 |\r\n| 矩形 | <code>rect</code> | 矩形对象 |\r\n| 圆形 | <code>circle</code> | 圆形对象 |\r\n| 三角形 | <code>triangle</code> | 三角形对象 |\r\n| 椭圆 | <code>ellipse</code> | 椭圆对象 |\r\n| 多边形 | <code>polygon</code> | 多边形对象 |</p>\n<h3>线条类</h3>\n<p>| 类型 | 类型标识 | 说明 |\r\n|------|----------|------|\r\n| 直线 | <code>f-line</code> | 直线对象 |\r\n| 箭头线 | <code>f-arrow</code> | 带箭头的直线 |\r\n| 三角箭头线 | <code>f-tri-arrow</code> | 带三角形箭头的直线 |</p>\n<h3>路径类</h3>\n<p>| 类型 | 类型标识 | 说明 |\r\n|------|----------|------|\r\n| SVG 路径 | <code>path</code> | SVG 路径对象，支持自定义形状 |</p>\n<h3>组合类</h3>\n<p>| 类型 | 类型标识 | 说明 |\r\n|------|----------|------|\r\n| 分组 | <code>group</code> | 多个对象的组合 |</p>\n<h3>特殊对象</h3>\n<p>| 类型 | 类型标识 | 说明 |\r\n|------|----------|------|\r\n| 画布背景 | <code>fabritor-sketch</code> | 画布背景矩形，不可选中 |</p>\n<h2>4. 对象属性列表</h2>\n<h3>通用属性</h3>\n<p>所有对象都支持以下属性：</p>\n<p>| 属性名 | 类型 | 说明 | 可设置 |\r\n|--------|------|------|--------|\r\n| <code>id</code> | string | 对象唯一 ID | 不可设置 |\r\n| <code>type</code> | string | 对象类型 | 不可设置 |\r\n| <code>left</code> | number | X 坐标位置 | ✓ |\r\n| <code>top</code> | number | Y 坐标位置 | ✓ |\r\n| <code>width</code> | number | 宽度 | ✓ |\r\n| <code>height</code> | number | 高度 | ✓ |\r\n| <code>scaleX</code> | number | X 轴缩放比例 | ✓ |\r\n| <code>scaleY</code> | number | Y 轴缩放比例 | ✓ |\r\n| <code>angle</code> | number | 旋转角度 (度) | ✓ |\r\n| <code>opacity</code> | number | 透明度 (0-1) | ✓ |\r\n| <code>fill</code> | string/Gradient | 填充颜色 | ✓ |\r\n| <code>stroke</code> | string | 描边颜色 | ✓ |\r\n| <code>strokeWidth</code> | number | 描边宽度 | ✓ |\r\n| <code>flipX</code> | boolean | 水平翻转 | ✓ |\r\n| <code>flipY</code> | boolean | 垂直翻转 | ✓ |\r\n| <code>visible</code> | boolean | 是否可见 | ✓ |\r\n| <code>selectable</code> | boolean | 是否可选中 | ✓ |</p>\n<h3>文本对象 (<code>f-text</code>) 特有属性</h3>\n<p>| 属性名 | 类型 | 说明 | 可设置 |\r\n|--------|------|------|--------|\r\n| <code>text</code> | string | 文本内容 | ✓ |\r\n| <code>fontFamily</code> | string | 字体名称 | ✓ |\r\n| <code>fontSize</code> | number | 字体大小 | ✓ |\r\n| <code>fontWeight</code> | string | 字体粗细 (<code>normal</code>/<code>bold</code>) | ✓ |\r\n| <code>fontStyle</code> | string | 字体样式 (<code>normal</code>/<code>italic</code>) | ✓ |\r\n| <code>textAlign</code> | string | 文本对齐 (<code>left</code>/<code>center</code>/<code>right</code>/<code>justify</code>) | ✓ |\r\n| <code>lineHeight</code> | number | 行高 | ✓ |\r\n| <code>charSpacing</code> | number | 字符间距 | ✓ |\r\n| <code>underline</code> | boolean | 下划线 | ✓ |\r\n| <code>overline</code> | boolean | 上划线 | ✓ |\r\n| <code>linethrough</code> | boolean | 删除线 | ✓ |\r\n| <code>styles</code> | object | 多行文本样式 | ✓ |</p>\n<h3>图片对象 (<code>f-image</code>) 特有属性</h3>\n<p>| 属性名 | 类型 | 说明 | 可设置 |\r\n|--------|------|------|--------|\r\n| <code>src</code> | string | 图片 URL | ✓ |\r\n| <code>imageSource</code> | string | 图片源数据 | 不可设置 |\r\n| <code>imageBorder</code> | object | 图片边框配置 | ✓ |</p>\n<p>图片边框配置 (<code>imageBorder</code>)：\r\n| 属性名 | 类型 | 说明 |\r\n|--------|------|------|\r\n| <code>stroke</code> | string | 边框颜色 |\r\n| <code>strokeWidth</code> | number | 边框宽度 |\r\n| <code>borderRadius</code> | number | 圆角半径 |\r\n| <code>strokeDashArray</code> | array | 虚线样式 |</p>\n<h3>线条对象 (<code>f-line</code>, <code>f-arrow</code>, <code>f-tri-arrow</code>) 特有属性</h3>\n<p>| 属性名 | 类型 | 说明 | 可设置 |\r\n|--------|------|------|--------|\r\n| <code>x1</code> | number | 起点 X 坐标 | ✓ |\r\n| <code>y1</code> | number | 起点 Y 坐标 | ✓ |\r\n| <code>x2</code> | number | 终点 X 坐标 | ✓ |\r\n| <code>y2</code> | number | 终点 Y 坐标 | ✓ |\r\n| <code>strokeLineCap</code> | string | 线端样式 (<code>butt</code>/<code>round</code>/<code>square</code>) | ✓ |\r\n| <code>strokeDashArray</code> | array | 虚线样式 | ✓ |</p>\n<h3>路径对象 (<code>path</code>) 特有属性</h3>\n<p>| 属性名 | 类型 | 说明 | 可设置 |\r\n|--------|------|------|--------|\r\n| <code>path</code> | object | SVG 路径数据 | ✓ |\r\n| <code>sub_type</code> | string | 路径子类型 | 不可设置 |</p>\n<h3>对象 ID 系统</h3>\n<p>画布上的每个对象都有一个唯一的、稳定的 ID，在操作期间保持不变。</p>\n<pre><code class=\"language-javascript\">// 对象自动获得 ID，如: 'obj_1234567890_1'\r\n\r\n// 获取所有对象及其 ID\r\nconst objects = window.fabritor.canvas.getObjects();\r\nobjects.forEach(obj => {\r\n  console.log(obj.id, obj.type);\r\n});\r\n\r\n// 使用 ID 在其他操作中引用对象\r\nwindow.fabritor.actions.setObjectProperty('obj_1234567890_1', 'left', 100);\n</code></pre>\n<h2>使用示例</h2>\n<h3>示例 1：将所有文本对象左对齐</h3>\n<pre><code class=\"language-javascript\">const textObjects = window.fabritor.canvas.getObjectsByType('f-text');\r\ntextObjects.forEach(obj => {\r\n  window.fabritor.actions.setObjectProperty(obj.id, 'textAlign', 'left');\r\n});\r\n// 或使用批量操作:\r\nwindow.fabritor.actions.updateObjectsByType('f-text', { textAlign: 'left' });\n</code></pre>\n<h3>示例 2：设置所有文本对象的 X 坐标</h3>\n<pre><code class=\"language-javascript\">window.fabritor.actions.updateObjectsByType('f-text', { left: 20 });\n</code></pre>\n<h3>示例 3：查找并修改特定对象</h3>\n<pre><code class=\"language-javascript\">const objects = window.fabritor.canvas.getObjects();\r\nconst target = objects.find(obj => obj.text === 'Hello World');\r\nif (target) {\r\n  window.fabritor.actions.setObjectProperties(target.id, {\r\n    fontSize: 60,\r\n    fill: '#FF0000'\r\n  });\r\n}\n</code></pre>\n<h3>示例 4：监听变化</h3>\n<pre><code class=\"language-javascript\">window.fabritor.events.on('object:modified', (data) => {\r\n  console.log('对象已修改:', data);\r\n});\n</code></pre>\n<h3>示例 5：修改后导出</h3>\n<pre><code class=\"language-javascript\">// 进行修改\r\nwindow.fabritor.actions.updateObjectsByType('f-text', { fontSize: 40 });\r\n\r\n// 导出\r\nconst img = window.fabritor.export.toImg();\r\n// 保存图片或发送到服务器\n</code></pre>";

export const jsonHtml = "<h1>Fabritor JSON 解析规则</h1>\n<h2>概述</h2>\n<p>Fabritor 基于 Fabric.js 构建，使用 JSON 格式进行画布状态的保存和加载。通过 JSON 格式，可以：</p>\n<ul>\n<li>导出设计结果为模板</li>\n<li>加载模板快速恢复设计</li>\n<li>实现撤销/重做功能</li>\n</ul>\n<h2>JSON 结构</h2>\n<h3>根级属性</h3>\n<pre><code class=\"language-json\">{\n  \"version\": \"5.3.0\",\n  \"fabritor_schema_version\": 3,\n  \"objects\": [...],\n  \"clipPath\": {...},\n  \"background\": \"#ddd\"\n}\n</code></pre>\n<p>| 属性 | 类型 | 说明 |\n|------|------|------|\n| <code>version</code> | string | Fabric.js 版本号 |\n| <code>fabritor_schema_version</code> | number | Fabritor 架构版本号（当前为 3） |\n| <code>objects</code> | array | 画布上的所有对象数组 |\n| <code>clipPath</code> | object | 画布裁剪路径（通常为 sketch 矩形） |\n| <code>background</code> | string | 画布背景色 |</p>\n<h2>自定义属性列表</h2>\n<p>以下属性会在 JSON 导出时被保留（定义在 <code>FABRITOR_CUSTOM_PROPS</code>）：</p>\n<ul>\n<li><code>id</code> - 对象唯一标识</li>\n<li><code>fabritor_desc</code> - 对象描述</li>\n<li><code>selectable</code> - 是否可选择</li>\n<li><code>hasControls</code> - 是否显示控制点</li>\n<li><code>sub_type</code> - 子类型（如 'rough' 手绘风格）</li>\n<li><code>imageSource</code> - 图片来源信息</li>\n<li><code>imageBorder</code> - 图片边框配置</li>\n<li><code>oldArrowInfo</code> - 箭头信息</li>\n</ul>\n<h2>Sketch（画布）对象</h2>\n<p>画布对象是 <code>id</code> 为 <code>fabritor-sketch</code> 的矩形对象：</p>\n<pre><code class=\"language-json\">{\n  \"type\": \"rect\",\n  \"left\": 0,\n  \"top\": 0,\n  \"width\": 1242,\n  \"height\": 1660,\n  \"fill\": \"#ffffff\",\n  \"id\": \"fabritor-sketch\",\n  \"fabritor_desc\": \"我的画板 by fabritor\",\n  \"selectable\": false,\n  \"hasControls\": false\n}\n</code></pre>\n<h3>Sketch 特殊属性</h3>\n<ul>\n<li><code>id</code>: 固定为 <code>\"fabritor-sketch\"</code></li>\n<li><code>fabritor_desc</code>: 画布描述文本（导出时用作文件名）</li>\n<li><code>selectable</code>: 始终为 <code>false</code></li>\n<li><code>hasControls</code>: 始终为 <code>false</code></li>\n</ul>\n<h2>对象类型</h2>\n<h3>1. FText（文字）</h3>\n<p><strong>类型</strong>: <code>\"f-text\"</code></p>\n<p><strong>基础属性</strong>:</p>\n<pre><code class=\"language-json\">{\n  \"type\": \"f-text\",\n  \"left\": 100,\n  \"top\": 100,\n  \"width\": 500,\n  \"height\": 80,\n  \"fill\": \"#000000\",\n  \"fontWeight\": \"normal\",\n  \"fontSize\": 50,\n  \"lineHeight\": 1.3,\n  \"textAlign\": \"center\",\n  \"fontFamily\": \"AlibabaPuHuiTi\",\n  \"text\": \"文字内容\",\n  \"charSpacing\": 0,\n  \"splitByGrapheme\": true,\n  \"opacity\": 1,\n  \"angle\": 0,\n  \"scaleX\": 1,\n  \"scaleY\": 1\n}\n</code></pre>\n<p><strong>文字样式</strong> (<code>styles</code> 数组格式):</p>\n<pre><code class=\"language-json\">{\n  \"styles\": [\n    {\"line\": 0, \"char\": 0, \"style\": {\"fontWeight\": \"bold\"}},\n    {\"line\": 1, \"char\": 2, \"style\": {\"fill\": \"#ff0000\"}}\n  ]\n}\n</code></pre>\n<p><strong>波浪形文字</strong> (<code>path</code> 属性):</p>\n<pre><code class=\"language-json\">{\n  \"path\": {\n    \"type\": \"path\",\n    \"path\": [[\"M\", 0, 0], [\"Q\", 50, -50, 100, 0]],\n    \"pathStartOffset\": 0,\n    \"pathSide\": \"left\",\n    \"pathAlign\": \"center\"\n  }\n}\n</code></pre>\n<p>| 属性 | 说明 |\n|------|------|\n| <code>fontFamily</code> | 字体名称（必须从预设列表中选择） |\n| <code>fontSize</code> | 字号 |\n| <code>fill</code> | 文字颜色（支持渐变对象） |\n| <code>textAlign</code> | 对齐方式：left/center/right |\n| <code>fontWeight</code> | 字重：normal/bold |\n| <code>fontStyle</code> | 字体样式：normal/italic |\n| <code>underline</code> | 下划线 |\n| <code>linethrough</code> | 删除线 |\n| <code>lineHeight</code> | 行高 |\n| <code>charSpacing</code> | 字间距 |\n| <code>splitByGrapheme</code> | 中文处理标志（始终为 true） |</p>\n<h3>2. FImage（图片）</h3>\n<p><strong>类型</strong>: <code>\"f-image\"</code></p>\n<p><strong>基础结构</strong>:</p>\n<pre><code class=\"language-json\">{\n  \"type\": \"f-image\",\n  \"left\": 100,\n  \"top\": 100,\n  \"objects\": [\n    {\n      \"type\": \"image\",\n      \"src\": \"data:image/png;base64,...\",\n      \"width\": 500,\n      \"height\": 500,\n      \"originX\": \"center\",\n      \"originY\": \"center\"\n    },\n    {\n      \"type\": \"rect\",\n      \"width\": 500,\n      \"height\": 500,\n      \"fill\": \"#00000000\",\n      \"stroke\": \"#ff0000\",\n      \"strokeWidth\": 5,\n      \"rx\": 20,\n      \"ry\": 20,\n      \"originX\": \"center\",\n      \"originY\": \"center\"\n    }\n  ],\n  \"imageBorder\": {\n    \"stroke\": \"#ff0000\",\n    \"strokeWidth\": 5,\n    \"borderRadius\": 20,\n    \"strokeDashArray\": null\n  },\n  \"opacity\": 1,\n  \"angle\": 0\n}\n</code></pre>\n<p><strong>图片边框配置</strong> (<code>imageBorder</code>):</p>\n<pre><code class=\"language-json\">{\n  \"stroke\": \"#ff0000\",        // 边框颜色\n  \"strokeWidth\": 5,           // 边框粗细\n  \"borderRadius\": 20,         // 圆角半径\n  \"strokeDashArray\": null      // 虚线数组，如 [5, 5]\n}\n</code></pre>\n<p><strong>图片滤镜</strong> (通过 <code>src</code> 对象的 <code>filters</code> 属性):</p>\n<pre><code class=\"language-json\">{\n  \"filters\": [\n    {\n      \"type\": \"Grayscale\"\n    }\n    // 或 \"Sepia\", \"Blur\", \"Brightness\", \"Contrast\" 等\n  ]\n}\n</code></pre>\n<h3>3. FLine（线条）</h3>\n<p><strong>类型</strong>: <code>\"f-line\"</code></p>\n<pre><code class=\"language-json\">{\n  \"type\": \"f-line\",\n  \"x1\": 100,\n  \"y1\": 100,\n  \"x2\": 300,\n  \"y2\": 300,\n  \"stroke\": \"#000000\",\n  \"strokeWidth\": 5,\n  \"strokeDashArray\": null,\n  \"strokeLineCap\": \"butt\",\n  \"strokeLineJoin\": \"miter\",\n  \"left\": 200,\n  \"top\": 200,\n  \"opacity\": 1\n}\n</code></pre>\n<p>| 属性 | 说明 |\n|------|------|\n| <code>x1</code>, <code>y1</code> | 起点坐标 |\n| <code>x2</code>, <code>y2</code> | 终点坐标 |\n| <code>stroke</code> | 线条颜色 |\n| <code>strokeWidth</code> | 线条粗细 |\n| <code>strokeDashArray</code> | 虚线数组（如 [10, 5] 表示 10px 实线 5px 虚线） |\n| <code>strokeLineCap</code> | 线帽样式：butt/round |</p>\n<h3>4. FArrow（箭头）</h3>\n<p><strong>类型</strong>: <code>\"f-arrow\"</code></p>\n<pre><code class=\"language-json\">{\n  \"type\": \"f-arrow\",\n  \"x1\": 100,\n  \"y1\": 100,\n  \"x2\": 300,\n  \"y2\": 300,\n  \"stroke\": \"#000000\",\n  \"strokeWidth\": 5,\n  \"strokeDashArray\": null,\n  \"strokeLineCap\": \"butt\",\n  \"strokeLineJoin\": \"miter\",\n  \"oldArrowInfo\": {\n    \"left\": -28,\n    \"top\": -15,\n    \"bottom\": 15,\n    \"strokeWidth\": 5\n  }\n}\n</code></pre>\n<p><strong>oldArrowInfo</strong> 保存箭头头部渲染信息：</p>\n<ul>\n<li><code>left</code>: 箭头头部相对于终点的 X 偏移</li>\n<li><code>top</code>: 箭头顶部 Y 偏移</li>\n<li><code>bottom</code>: 箭头底部 Y 偏移</li>\n<li><code>strokeWidth</code>: 渲染时的线宽</li>\n</ul>\n<h3>5. FTriArrow（三角箭头）</h3>\n<p><strong>类型</strong>: <code>\"f-tri-arrow\"</code></p>\n<p>结构与 FArrow 相同，但箭头头部为三角形：</p>\n<pre><code class=\"language-json\">{\n  \"type\": \"f-tri-arrow\",\n  \"x1\": 100,\n  \"y1\": 100,\n  \"x2\": 300,\n  \"y2\": 300,\n  \"stroke\": \"#000000\",\n  \"strokeWidth\": 5,\n  \"oldArrowInfo\": {\n    \"left\": -24,\n    \"top\": -16,\n    \"bottom\": 16,\n    \"strokeWidth\": 5\n  }\n}\n</code></pre>\n<h3>6. 基础形状</h3>\n<p><strong>类型</strong>: <code>\"rect\"</code>, <code>\"circle\"</code>, <code>\"triangle\"</code>, <code>\"polygon\"</code>, <code>\"ellipse\"</code></p>\n<pre><code class=\"language-json\">{\n  \"type\": \"rect\",\n  \"left\": 100,\n  \"top\": 100,\n  \"width\": 200,\n  \"height\": 150,\n  \"fill\": \"#ff0000\",\n  \"stroke\": \"#000000\",\n  \"strokeWidth\": 2,\n  \"rx\": 10,\n  \"ry\": 10,\n  \"opacity\": 1,\n  \"angle\": 0\n}\n</code></pre>\n<p>| 属性 | 说明 |\n|------|------|\n| <code>fill</code> | 填充颜色（支持渐变） |\n| <code>stroke</code> | 描边颜色 |\n| <code>strokeWidth</code> | 描边粗细 |\n| <code>rx</code>, <code>ry</code> | 圆角半径（仅 rect） |</p>\n<h3>7. Path（画笔路径）</h3>\n<p><strong>类型</strong>: <code>\"path\"</code></p>\n<pre><code class=\"language-json\">{\n  \"type\": \"path\",\n  \"path\": [[\"M\", 100, 100], [\"L\", 150, 150], [\"Q\", 200, 200, 250, 150]],\n  \"stroke\": \"#000000\",\n  \"strokeWidth\": 3,\n  \"fill\": null,\n  \"strokeLineCap\": \"round\",\n  \"strokeLineJoin\": \"round\",\n  \"sub_type\": \"rough\"  // 可选：表示手绘风格\n}\n</code></pre>\n<p><strong>sub_type</strong>:</p>\n<ul>\n<li>未设置：普通画笔路径</li>\n<li><code>\"rough\"</code>：手绘风格路径</li>\n</ul>\n<h3>8. Group（组合）</h3>\n<p><strong>类型</strong>: <code>\"group\"</code></p>\n<pre><code class=\"language-json\">{\n  \"type\": \"group\",\n  \"left\": 100,\n  \"top\": 100,\n  \"objects\": [\n    // 包含的子对象\n  ],\n  \"sub_type\": \"rough\"  // 可选\n}\n</code></pre>\n<h2>通用对象属性</h2>\n<p>所有对象都支持以下属性：</p>\n<p>| 属性 | 类型 | 说明 |\n|------|------|------|\n| <code>left</code> | number | X 坐标 |\n| <code>top</code> | number | Y 坐标 |\n| <code>width</code> | number | 宽度 |\n| <code>height</code> | number | 高度 |\n| <code>scaleX</code> | number | 水平缩放 |\n| <code>scaleY</code> | number | 垂直缩放 |\n| <code>angle</code> | number | 旋转角度（度） |\n| <code>flipX</code> | boolean | 水平翻转 |\n| <code>flipY</code> | boolean | 垂直翻转 |\n| <code>opacity</code> | number | 透明度（0-1） |\n| <code>shadow</code> | object/null | 阴影配置 |</p>\n<p><strong>阴影配置</strong>:</p>\n<pre><code class=\"language-json\">{\n  \"shadow\": {\n    \"color\": \"#000000\",\n    \"blur\": 10,\n    \"offsetX\": 5,\n    \"offsetY\": 5\"\n  }\n}\n</code></pre>\n<h2>渐变填充</h2>\n<p>对象可以设置线性或径向渐变：</p>\n<h3>线性渐变</h3>\n<pre><code class=\"language-json\">{\n  \"fill\": {\n    \"type\": \"linear\",\n    \"gradientUnits\": \"percentage\",\n    \"coords\": {\n      \"x1\": 0,\n      \"y1\": 1,\n      \"x2\": 1,\n      \"y2\": 0\n    },\n    \"colorStops\": [\n      { \"offset\": 0, \"color\": \"#667eea\" },\n      { \"offset\": 1, \"color\": \"#764ba2\" }\n    ]\n  }\n}\n</code></pre>\n<h3>径向渐变</h3>\n<pre><code class=\"language-json\">{\n  \"fill\": {\n    \"type\": \"radial\",\n    \"gradientUnits\": \"percentage\",\n    \"coords\": {\n      \"x1\": 0.5,\n      \"y1\": 0.5,\n      \"x2\": 0.5,\n      \"y2\": 0.5,\n      \"r1\": 0,\n      \"r2\": 1\n    },\n    \"colorStops\": [\n      { \"offset\": 0, \"color\": \"#f6d365\" },\n      { \"offset\": 1, \"color\": \"#fda085\" }\n    ]\n  }\n}\n</code></pre>\n<h3>角度与坐标映射</h3>\n<p>| 角度 | coords |\n|------|--------|\n| 45° | {x1: 0, y1: 1, x2: 1, y2: 0} |\n| 90° | {x1: 0, y1: 0, x2: 1, y2: 0} |\n| 135° | {x1: 0, y1: 0, x2: 1, y2: 1} |\n| 180° | {x1: 0, y1: 0, x2: 0, y2: 1} |</p>\n<h2>版本控制</h2>\n<p><strong>schema_version</strong>: 用于检测 JSON 格式的兼容性</p>\n<ul>\n<li>当前版本：3</li>\n<li>加载时如果版本不匹配，会显示警告并拒绝加载</li>\n</ul>\n<h2>使用示例</h2>\n<h3>导出 JSON</h3>\n<pre><code class=\"language-javascript\">const json = editor.canvas2Json();\nconst jsonStr = JSON.stringify(json, null, 2);\n</code></pre>\n<h3>加载 JSON</h3>\n<pre><code class=\"language-javascript\">await editor.loadFromJSON(jsonString, true);\n</code></pre>\n<p>参数说明：</p>\n<ul>\n<li>第一个参数：JSON 对象或字符串</li>\n<li>第二个参数：是否显示错误提示</li>\n<li>加载过程中会自动加载字体（如果 <code>LOAD_JSON_IGNORE_LOAD_FONT</code> 为 false）</li>\n</ul>\n<h3>模板保存与加载</h3>\n<p>导出时使用 sketch 的 <code>fabritor_desc</code> 属性作为文件名：</p>\n<pre><code class=\"language-javascript\">const name = sketch.fabritor_desc; // \"我的画板 by fabritor\"\ndownloadFile(jsonStr, 'json', name);\n</code></pre>\n<h2>注意事项</h2>\n<ol>\n<li><strong>字体加载</strong>：文字对象的字体必须从预设列表中选择，加载 JSON 时会自动加载所需字体</li>\n<li><strong>图片数据</strong>：图片以 base64 格式存储在 <code>src</code> 属性中</li>\n<li><strong>自定义对象序列化</strong>：自定义对象通过重写 <code>toObject</code> 和 <code>fromObject</code> 方法实现序列化</li>\n<li><strong>性能考虑</strong>：大量对象导出时建议压缩，避免传输过大的 JSON 文件</li>\n</ol>\n<h2>html定位</h2>\n<p>JSON展示/修改控件</p>\n<ul>\n<li>json-panel-display - 只读模式的JSON展示区域（pre标签）</li>\n<li>json-panel-textarea - 编辑模式的JSON输入框（TextArea）\n按钮ID</li>\n<li>json-panel-btn-copy - 复制按钮</li>\n<li>json-panel-btn-edit - 编辑按钮（非编辑模式显示）</li>\n<li>json-panel-btn-cancel - 取消按钮（编辑模式显示）</li>\n<li>json-panel-btn-apply - 应用按钮（编辑模式显示）\n这些ID使用了统一的命名规范 json-panel-*，便于通过JavaScript或其他自动化工具进行定位和操作</li>\n</ul>";
